import { useState } from 'react';

const inputClasses = "w-full px-4 py-3 border border-gray-300 rounded-xl focus:ring-2 focus:ring-yellow-400 focus:border-transparent outline-none transition-all";
const labelClasses = "block text-sm font-medium text-gray-700 mb-2";

export default function LeadForm() {
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    phone: '',
    company: '',
    status: '',
    activity: '',
    situation: ''
  });
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isSuccess, setIsSuccess] = useState(false);

  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setIsSubmitting(true);

    try {
      const response = await fetch('/api/leads', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(formData)
      });

      if (response.ok) {
        setIsSuccess(true);
        setFormData({ name: '', email: '', phone: '', company: '', status: '', activity: '', situation: '' });
      }
    } catch (error) {
      console.error('Submission error:', error);
    } finally {
      setIsSubmitting(false);
    }
  };

  if (isSuccess) {
    return (
      <section id="quote" className="py-16 bg-gray-50">
        <div className="max-w-lg mx-auto px-4">
          <div className="bg-white rounded-2xl shadow-xl p-8 text-center">
            <div className="w-16 h-16 bg-green-100 rounded-full flex items-center justify-center mx-auto mb-4">
              <span className="text-3xl">✓</span>
            </div>
            <h3 className="text-2xl font-bold text-gray-900 mb-2">Merci !</h3>
            <p className="text-gray-600 mb-4">
              Votre demande a été transmise. Un expert vous contactera sous 24h pour votre devis personnalisé.
            </p>
            <button onClick={() => setIsSuccess(false)} className="text-blue-800 font-medium hover:underline">
              Envoyer une autre demande
            </button>
          </div>
        </div>
      </section>
    );
  }

  return (
    <section id="quote" className="py-16 bg-gray-50">
      <div className="max-w-4xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="text-center mb-10">
          <h2 className="text-3xl md:text-4xl font-bold text-gray-900">
            Obtenez votre <span className="text-blue-800">devis gratuit</span>
          </h2>
          <p className="mt-3 text-gray-600 text-lg">
            Remplissez le formulaire pour comparer les meilleures offres d'assurance
          </p>
        </div>

        <div className="bg-white rounded-2xl shadow-xl p-6 md:p-10">
          <form onSubmit={handleSubmit} className="space-y-6">
            <div className="grid md:grid-cols-2 gap-6">
              <div>
                <label htmlFor="name" className={labelClasses}>Nom complet *</label>
                <input
                  type="text"
                  id="name"
                  name="name"
                  required
                  value={formData.name}
                  onChange={handleChange}
                  className={inputClasses}
                  placeholder="Votre nom"
                />
              </div>
              <div>
                <label htmlFor="email" className={labelClasses}>Email *</label>
                <input
                  type="email"
                  id="email"
                  name="email"
                  required
                  value={formData.email}
                  onChange={handleChange}
                  className={inputClasses}
                  placeholder="votre@email.com"
                />
              </div>
            </div>

            <div className="grid md:grid-cols-2 gap-6">
              <div>
                <label htmlFor="phone" className={labelClasses}>Téléphone *</label>
                <input
                  type="tel"
                  id="phone"
                  name="phone"
                  required
                  value={formData.phone}
                  onChange={handleChange}
                  className={inputClasses}
                  placeholder="06 12 34 56 78"
                />
              </div>
              <div>
                <label htmlFor="company" className={labelClasses}>Entreprise (optionnel)</label>
                <input
                  type="text"
                  id="company"
                  name="company"
                  value={formData.company}
                  onChange={handleChange}
                  className={inputClasses}
                  placeholder="Nom de votre société"
                />
              </div>
            </div>

            <div className="grid md:grid-cols-3 gap-6">
              <div>
                <label htmlFor="status" className={labelClasses}>Statut actuel</label>
                <select
                  id="status"
                  name="status"
                  value={formData.status}
                  onChange={handleChange}
                  className={inputClasses}
                >
                  <option value="">Sélectionner...</option>
                  <option value="new">Nouveau chauffeur</option>
                  <option value="existing">Chauffeur actuel</option>
                  <option value="resiliated">Résilié</option>
                  <option value="malus">Avec malus</option>
                </select>
              </div>
              <div>
                <label htmlFor="activity" className={labelClasses}>Activité</label>
                <select
                  id="activity"
                  name="activity"
                  value={formData.activity}
                  onChange={handleChange}
                  className={inputClasses}
                >
                  <option value="">Sélectionner...</option>
                  <option value="taxi">Taxi</option>
                  <option value="vtc">VTC</option>
                  <option value="ambulance">Ambulance</option>
                  <option value="transport">Transport scolaire</option>
                </select>
              </div>
              <div>
                <label htmlFor="situation" className={labelClasses}>Situation</label>
                <select
                  id="situation"
                  name="situation"
                  value={formData.situation}
                  onChange={handleChange}
                  className={inputClasses}
                >
                  <option value="">Sélectionner...</option>
                  <option value="auto">Auto-entrepreneur</option>
                  <option value="sarl">SARL</option>
                  <option value="eurl">EURL</option>
                  <option value="other">Autre</option>
                </select>
              </div>
            </div>

            <button
              type="submit"
              disabled={isSubmitting}
              className="w-full btn-primary text-lg py-4 disabled:opacity-50 disabled:cursor-not-allowed"
            >
              {isSubmitting ? 'Envoi en cours...' : 'Comparer maintenant'}
            </button>

            <p className="text-center text-sm text-gray-500">
              🔒 Vos données sont protégées. Conformément au RGPD, nous ne communiquerons jamais vos informations.
            </p>
          </form>
        </div>
      </div>
    </section>
  );
}
